// src/App.js

import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import EventManage from './components/EventManage'; // EventManageコンポbytes:\xe3\x83\xbc\xe3\x83bytes:\x8dントをインポート
import EventDetail from './components/EventDetail'; // EventDetailコンポbytes:\xe3\x83\xbc\xe3\x83bytes:\x8dントをインポート
import EventRegister from './components/EventRegister'; // EventRegisterコンポbytes:\xe3\x83\xbc\xe3\x83bytes:\x8dントをインポート

function App() {
  return (
    <Router>
      <div className="App">
        <Routes>
          <Route path="/" element={<EventManage />} index />
          <Route path="/event/:id" element={<EventDetail />} />
          <Route path="/event/register" element={<EventRegister />} />
        </Routes>
      </div>
    </Router>
  );
}

export default App;
